mapper.select:
SELECT a.id AS id, a.title AS title, a.cover_url AS coverUrl, a.price AS price, a.trial_duration AS trialDuration, a.view_count AS viewCount, a.create_time AS createTime, u.id AS `creator.id`, u.username AS `creator.username`, u.nickname AS `creator.nickname`, u.avatar AS `creator.avatar` FROM audio_info a LEFT JOIN sys_user u ON a.creator_id = u.id WHERE a.is_deleted = 0 AND a.visible = 1 AND a.audit_status = 1 AND a.status = 2
AND a.title LIKE CONCAT('%', #{query.title}, '%')
AND EXISTS ( SELECT 1 FROM audio_tag_relation atr JOIN sys_tag t ON atr.tag_id = t.id WHERE atr.audio_id = a.id AND t.name IN
#{tag}
)
ORDER BY a.create_time DESC
